// The MATLAB v4 reader lives in a sibling file. lib.rs is regenerated by
// mmtorust and only declares the top-level packages, so the submodule is
// attached here instead. Same for the CSV/PLT readers.
// `pub` so the embedding cdylib (libopenmodelica_compiler) can wrap these in the
// C `ModelicaMatReader` / csv ABI OMEdit links against.
#[path = "read_matlab4.rs"]
pub mod read_matlab4;
use read_matlab4::MatReader;
#[path = "result_readers.rs"]
pub mod result_readers;
use result_readers::{CsvReader, PltReader, PltVal};

fn write_output_file(path: &str, bytes: &[u8]) -> std::io::Result<()> {
    openmodelica_wasi::fs::write(path, bytes)
}

