/// The result-file reader behind every entry point, dispatched by file
/// suffix exactly like `SimulationResultsImpl__openFile` (.mat / .plt /
/// .csv; anything else is the `Unknown result-file suffix` error).
enum ResultReader {
    Mat(MatReader),
    Plt(PltReader),
    Csv(CsvReader),
}

enum OpenError {
    UnknownSuffix,
    Failed(String),
}

impl ResultReader {
    fn open(filename: &str) -> Result<ResultReader, OpenError> {
        if filename.ends_with(".mat") {
            MatReader::open(filename).map(ResultReader::Mat).map_err(OpenError::Failed)
        } else if filename.ends_with(".plt") {
            PltReader::open(filename).map(ResultReader::Plt).map_err(OpenError::Failed)
        } else if filename.ends_with(".csv") {
            CsvReader::open(filename).map(ResultReader::Csv).map_err(OpenError::Failed)
        } else {
            Err(OpenError::UnknownSuffix)
        }
    }

    /// Open with the same two scripting errors `SimulationResultsImpl__openFile`
    /// raises (unknown suffix / failed to open); `None` after reporting.
    fn open_reporting(filename: &ArcStr) -> Result<Option<ResultReader>> {
        match ResultReader::open(filename.as_str()) {
            Ok(r) => Ok(Some(r)),
            Err(OpenError::UnknownSuffix) => {
                err(&ERROR_UNKNOWN_SUFFIX, [filename.clone()])?;
                Ok(None)
            }
            Err(OpenError::Failed(e)) => {
                err(&ERROR_OPEN_FAILED, [filename.clone(), ArcStr::from(e)])?;
                Ok(None)
            }
        }
    }

    /// Sample-point count: `nrows` / `numsteps` / the PLT `#IntervalSize`
    /// (`None` when that line is missing or zero).
    fn nrows(&self) -> Option<usize> {
        match self {
            ResultReader::Mat(r) => Some(r.nrows),
            ResultReader::Csv(r) => Some(r.numsteps),
            ResultReader::Plt(r) => r.interval_size(),
        }
    }
}

/// The process-global reader cache mirroring the C `simresglob` "super cache":
/// repeated `val()`/`readDataset()` calls on the same unchanged file reuse the
/// parsed reader. Guarded by a `Mutex` for thread safety. These functions run
/// at script level (CevalScript), never on a compiler hot path, so taking the
/// lock across the file read is fine. [`close`] clears it.
struct CachedReader {
    fileName: ArcStr,
    mtime: Option<SystemTime>,
    reader: ResultReader,
}
static READER_CACHE: Mutex<Option<CachedReader>> = Mutex::new(None);

fn err(msg: &ErrorTypes::Message, tokens: impl IntoIterator<Item = ArcStr>) -> Result<()> {
    Error::addMessage(msg.clone(), Arc::new(List::from_iter(tokens)))
}

/// Lock the cache and ensure it holds an open reader for `filename`, reopening
/// when the path or mtime changed. Returns `None` (after emitting a scripting
/// error) for unsupported suffixes or open failures.
fn lock_reader(filename: &ArcStr) -> Result<Option<MutexGuard<'static, Option<CachedReader>>>> {
    let mtime = openmodelica_wasi::fs::modified(filename.as_str()).ok();
    let mut guard = READER_CACHE.lock().unwrap();
    let reuse = matches!(&*guard, Some(c)
        if c.fileName == *filename && mtime.is_some() && c.mtime == mtime);
    if !reuse {
        match ResultReader::open_reporting(filename)? {
            Some(reader) => {
                *guard = Some(CachedReader { fileName: filename.clone(), mtime, reader });
            }
            None => {
                *guard = None;
                return Ok(None);
            }
        }
    }
    Ok(Some(guard))
}

/// Build a `Values.REAL`.
fn mk_real(x: f64) -> Arc<Values::Value> {
    Arc::new(Values::REAL { real: OrderedFloat(x) })
}

/// Wrap a row of `Values` in a `Values.ARRAY`, mirroring `ValuesMake.makeArray`:
/// the new outer dimension is prepended to the inner array's `dimLst`.
fn make_array(vals: Vec<Arc<Values::Value>>) -> Arc<Values::Value> {
    let n = vals.len() as i32;
    let inner_dims: Arc<List<i32>> = match vals.first().map(|v| &**v) {
        Some(Values::ARRAY { dimLst, .. }) => dimLst.clone(),
        _ => Arc::new(List::Nil),
    };
    Arc::new(Values::ARRAY {
        valueLst: Arc::new(List::from_iter(vals)),
        dimLst: metamodelica::cons(n, inner_dims),
    })
}

pub fn val(mut filename: ArcStr, mut varname: ArcStr, mut timeStamp: metamodelica::Real) -> Result<metamodelica::Real> {
    // C: SimulationResults_val — read one variable's value at a given time
    // (with linear interpolation between sample points) from the cached
    // result file. On any error the C code emits a scripting message and
    // returns NaN; the script continues.
    let mut guard = match lock_reader(&filename)? {
        Some(g) => g,
        None => return Ok(OrderedFloat(f64::NAN)),
    };
    let t = timeStamp.into_inner();
    match &mut guard.as_mut().unwrap().reader {
        ResultReader::Mat(reader) => {
            let var = match reader.find_var(varname.as_str()) {
                Some(v) => v,
                None => {
                    drop(guard);
                    err(&ERROR_VAR_NOT_FOUND, [varname.clone(), filename.clone()])?;
                    return Ok(OrderedFloat(f64::NAN));
                }
            };
            match reader.val(var, t) {
                Some(v) => Ok(OrderedFloat(v)),
                None => {
                    let start = reader.start_time();
                    let stop = reader.stop_time();
                    drop(guard);
                    err(
                        &ERROR_VAL_NOT_DEFINED,
                        [
                            varname.clone(),
                            ArcStr::from(format_g(t)),
                            ArcStr::from(format_g(start)),
                            ArcStr::from(format_g(stop)),
                        ],
                    )?;
                    Ok(OrderedFloat(f64::NAN))
                }
            }
        }
        ResultReader::Plt(reader) => {
            let res = reader.val(varname.as_str(), t);
            drop(guard);
            match res {
                PltVal::Value(v) => Ok(OrderedFloat(v)),
                PltVal::NotFound => {
                    err(&ERROR_VAR_NOT_FOUND, [varname.clone(), filename.clone()])?;
                    Ok(OrderedFloat(f64::NAN))
                }
                PltVal::NotDefined => {
                    err(&ERROR_VAL_NOT_DEFINED_PLT, [varname.clone(), ArcStr::from(format_g(t))])?;
                    Ok(OrderedFloat(f64::NAN))
                }
            }
        }
        // The C val() has no CSV branch and reports the format as
        // unimplemented.
        ResultReader::Csv(_) => {
            drop(guard);
            err(&ERROR_VAL_NOT_IMPL, [literal!("CSV")])?;
            Ok(OrderedFloat(f64::NAN))
        }
    }
}

pub fn readVariables(mut filename: ArcStr, mut readParameters: bool, mut openmodelicaStyle: bool) -> Result<Arc<metamodelica::List<ArcStr>>> {
    // C: SimulationResults_readVariables — list the variable names stored in
    // a result file (sorted), optionally including parameters and converting
    // der()-style names to OpenModelica style.
    let mut guard = match lock_reader(&filename)? {
        Some(g) => g,
        None => return Ok(Arc::new(List::Nil)),
    };
    // C `makeOMCStyle`.
    let omc_style = |name: &str| -> ArcStr {
        if openmodelicaStyle {
            let converted =
                read_matlab4::openmodelica_style_name(name).unwrap_or_else(|| name.to_owned());
            ArcStr::from(converted.replace(' ', ""))
        } else {
            ArcStr::from(name)
        }
    };
    let mut names: Vec<ArcStr> = Vec::new();
    match &guard.as_ref().unwrap().reader {
        ResultReader::Mat(reader) => {
            for info in &reader.allInfo {
                if readParameters || !info.isParam {
                    names.push(omc_style(&info.name));
                }
            }
        }
        // PLT: `read_ptolemy_variables` conses while scanning and never
        // reverses, so the names come back in reverse document order; the
        // C comment says to assume they are already in OMC style.
        ResultReader::Plt(reader) => {
            names = reader.variables().into_iter().rev().map(ArcStr::from).collect();
        }
        // CSV: the header cells, skipping empty names (a trailing
        // delimiter on the header line).
        ResultReader::Csv(reader) => {
            names = reader.variables.iter().filter(|v| !v.is_empty()).map(|v| omc_style(v)).collect();
        }
    }
    Ok(Arc::new(List::from_iter(names)))
}

pub fn readDataset(mut filename: ArcStr, mut vars: Arc<metamodelica::List<ArcStr>>, mut dimsize: i32) -> Result<Arc<Values::Value>> {
    // C: SimulationResults_readDataset — read the full trajectories of the
    // given variables, returning a Values.ARRAY matrix (variable-major rows,
    // time-major columns). This combines the external `readDataset_work`
    // result with the `ValuesMake.makeReal`/`makeArray` conversion the MM
    // `readDataset` wrapper performed.
    let mut guard = match lock_reader(&filename)? {
        Some(g) => g,
        None => bail!("readDataset: could not open {filename}"),
    };
    match &mut guard.as_mut().unwrap().reader {
        ResultReader::Mat(reader) => {
            let mut dim = dimsize;
            if dim == 0 {
                dim = reader.nrows as i32;
            } else if reader.nrows as i32 != dim {
                drop(guard);
                err(&ERROR_DIMSIZE_MISMATCH, [])?;
                bail!("readDataset: dimension size mismatch for {filename}");
            }
            let dim = dim as usize;
            let mut rows: Vec<Arc<Values::Value>> = Vec::new();
            for var in vars.as_ref() {
                let idx = match reader.find_var(var.as_str()) {
                    Some(i) => i,
                    None => {
                        drop(guard);
                        err(&ERROR_COULD_NOT_READ_VAR, [var.clone(), filename.clone()])?;
                        bail!("readDataset: variable {var} not found in {filename}");
                    }
                };
                let info = &reader.allInfo[idx];
                let isParam = info.isParam;
                let index = info.index;
                let col: Vec<Arc<Values::Value>> = if isParam {
                    let p = reader.params[(index.unsigned_abs() as usize) - 1];
                    let p = if index < 0 { -p } else { p };
                    (0..dim).map(|_| mk_real(p)).collect()
                } else {
                    let vals = match reader.read_vals(index) {
                        Some(v) => v,
                        None => {
                            drop(guard);
                            err(&ERROR_COULD_NOT_READ_VAR, [var.clone(), filename.clone()])?;
                            bail!("readDataset: could not read variable {var} in {filename}");
                        }
                    };
                    (0..dim).map(|i| mk_real(vals[i])).collect()
                };
                rows.push(make_array(col));
            }
            Ok(make_array(rows))
        }
        ResultReader::Plt(reader) => {
            // `read_ptolemy_dataset`: dimsize 0 takes the file's
            // #IntervalSize; a nonzero dimsize must match it.
            let interval = reader.interval_size();
            let dim = if dimsize == 0 {
                interval.unwrap_or(0)
            } else {
                let Some(interval) = interval else {
                    drop(guard);
                    err(&ERROR_PLT_INTERVAL_READ, [])?;
                    bail!("readDataset: could not read interval size of {filename}");
                };
                if interval as i32 != dimsize {
                    drop(guard);
                    err(&ERROR_PLT_INTERVAL_MISMATCH, [])?;
                    bail!("readDataset: interval size not matching data size for {filename}");
                }
                interval
            };
            let mut rows: Vec<Arc<Values::Value>> = Vec::new();
            for var in vars.as_ref() {
                let Some(vals) = reader.dataset(var.as_str(), dim) else {
                    drop(guard);
                    err(&ERROR_PLT_VAR_NOT_FOUND, [var.clone()])?;
                    bail!("readDataset: variable {var} not found in {filename}");
                };
                rows.push(make_array(vals.into_iter().map(mk_real).collect()));
            }
            Ok(make_array(rows))
        }
        ResultReader::Csv(reader) => {
            // The C CSV branch reads `dimsize` cells from each column
            // without any bounds check (dimsize 0 yields empty columns,
            // dimsize > numsteps reads out of bounds). Mirror the empty
            // case, but turn the out-of-bounds read into an error.
            let dim = dimsize as usize;
            let mut rows: Vec<Arc<Values::Value>> = Vec::new();
            for var in vars.as_ref() {
                let col = match reader.dataset(var.as_str()) {
                    Some(c) if dim <= c.len() => &c[..dim],
                    _ => {
                        drop(guard);
                        err(&ERROR_COULD_NOT_READ_VAR, [var.clone(), filename.clone()])?;
                        bail!("readDataset: could not read variable {var} in {filename}");
                    }
                };
                rows.push(make_array(col.iter().copied().map(mk_real).collect()));
            }
            Ok(make_array(rows))
        }
    }
}

pub fn readSimulationResultSize(mut filename: ArcStr) -> Result<i32> {
    // C: SimulationResults_readSimulationResultSize — number of sample
    // points (rows) in a result file; -1 if it cannot be opened.
    let mut guard = match lock_reader(&filename)? {
        Some(g) => g,
        None => return Ok(-1),
    };
    match guard.as_ref().unwrap().reader.nrows() {
        Some(n) => Ok(n as i32),
        None => {
            // PLT without a usable #IntervalSize line.
            drop(guard);
            err(&ERROR_READ_SIZE_FAILED, [filename.clone()])?;
            Ok(-1)
        }
    }
}

pub fn close() {
    // C: SimulationResultsImpl__close(&simresglob) — drop the process-global
    // cached result-file handle so the next read (possibly of a re-run
    // simulation's fresh file) reopens it, and so the OS file handle is
    // released between `simulate()` calls.
    *READER_CACHE.lock().unwrap() = None;
}

/// Format a double the way C's `%g` does, for error-message interpolation.
fn format_g(x: f64) -> String {
    // Rust has no direct `%g`; this matches the common cases (finite values use
    // the shortest round-tripping representation, which is close enough for the
    // diagnostic text). Non-finite values print like C.
    if x.is_nan() {
        "nan".to_string()
    } else if x.is_infinite() {
        if x < 0.0 { "-inf".to_string() } else { "inf".to_string() }
    } else {
        format!("{x}")
    }
}

/// C `%.*g` with `sig` significant digits: fixed notation when the decimal
/// exponent is in `[-4, sig)`, exponential (`e±NN`, two-digit exponent)
/// otherwise, with trailing zeros stripped in both forms. Used for the data
/// values (sig=15, i.e. `%.15g`) and tolerance text (sig=2) of the HTML report.
fn format_g_prec(x: f64, sig: usize) -> String {
    if !x.is_finite() {
        return format_g(x);
    }
    if x == 0.0 {
        return "0".to_string();
    }
    let sig = sig.max(1);
    let exp = x.abs().log10().floor() as i32;
    if exp < -4 || exp >= sig as i32 {
        // Exponential. Rust prints `8.00e-7`; C `%g` prints `8e-07`: strip the
        // mantissa's trailing zeros and pad the exponent to two digits.
        let s = format!("{:.*e}", sig - 1, x);
        let (mant, e) = s.split_once('e').unwrap();
        let mant = if mant.contains('.') {
            mant.trim_end_matches('0').trim_end_matches('.')
        } else {
            mant
        };
        let e: i32 = e.parse().unwrap_or(0);
        format!("{mant}e{}{:02}", if e < 0 { '-' } else { '+' }, e.abs())
    } else {
        let decimals = (sig as i32 - 1 - exp).max(0) as usize;
        let s = format!("{:.*}", decimals, x);
        if s.contains('.') {
            s.trim_end_matches('0').trim_end_matches('.').to_string()
        } else {
            s
        }
    }
}

/// `%.15g`, the format C uses for the numeric data/time values in the report.
fn format_g_prec15(x: f64) -> String {
    format_g_prec(x, 15)
}

// ---------------------------------------------------------------------------
// Result comparison (port of SimulationResultsCmp.c)
//
// `cmpSimulationResults` is the `isResultCmp=1` path of the C
// `SimulationResultsCmp_compareResults`; it uses `cmpData` (event-aware
// point-by-point comparison with reference interpolation). `deltaSimulationResults`
// is `SimulationResultsCmp_deltaResults` (norm of the difference). Both open
// two independent readers (not the shared `READER_CACHE`, which only holds one
// file) since they compare a result file against a reference simultaneously.
// ---------------------------------------------------------------------------

// almostEqualRelativeAndAbs default tolerances (SimulationResultsCmp.c).
const DOUBLEEQUAL_TOTAL: f64 = 0.0000000001;
const DOUBLEEQUAL_REL: f64 = 0.00001;

/// C `almostEqualRelativeAndAbs`.
fn almost_equal_rel_abs(a: f64, b: f64, reltol: f64, abstol: f64) -> bool {
    let diff = (a - b).abs();
    diff <= abstol || diff <= a.abs().max(b.abs()) * reltol
}

/// C `almostEqualWithDefaultTolerance`.
fn almost_equal_default(a: f64, b: f64) -> bool {
    almost_equal_rel_abs(a, b, DOUBLEEQUAL_REL, DOUBLEEQUAL_TOTAL)
}

/// One row of the diff log, mirroring C `DiffData`.
struct DiffData {
    name: ArcStr,
    data: f64,
    dataref: f64,
    time: f64,
    timeref: f64,
    interpolate: bool,
}

/// C `getData`: full trajectory of `varname` over all `nrows` sample points
/// (a constant vector for parameters), or `None` if the variable is missing.
/// The filename to show in messages: `basename` under the testsuite, otherwise
/// the full path. Matches the C `runningTestsuite ? SystemImpl__basename(f) : f`.
fn display_filename(running_testsuite: bool, f: &ArcStr) -> ArcStr {
    if running_testsuite { openmodelica_util::System::basename(f.clone()) } else { f.clone() }
}

/// C `getData` → `SimulationResultsImpl__readDataset` for a single variable.
/// Returns the trajectory, or `None` after emitting the per-format error the
/// readDataset branch emits when a variable cannot be read (`file_msg`
/// already in display form).
fn get_data(reader: &mut ResultReader, varname: &str, file_msg: &ArcStr) -> Result<Option<Vec<f64>>> {
    match reader {
        ResultReader::Mat(reader) => get_data_mat(reader, varname, file_msg),
        ResultReader::Plt(reader) => {
            let nrows = reader.interval_size().unwrap_or(0);
            match reader.dataset(varname, nrows) {
                Some(v) => Ok(Some(v)),
                None => {
                    err(&ERROR_PLT_VAR_NOT_FOUND, [ArcStr::from(varname)])?;
                    Ok(None)
                }
            }
        }
        ResultReader::Csv(reader) => match reader.dataset(varname) {
            Some(v) => Ok(Some(v.to_vec())),
            None => {
                err(&ERROR_COULD_NOT_READ_VAR, [ArcStr::from(varname), file_msg.clone()])?;
                Ok(None)
            }
        },
    }
}

fn get_data_mat(reader: &mut MatReader, varname: &str, file_msg: &ArcStr) -> Result<Option<Vec<f64>>> {
    let Some(idx) = reader.find_var(varname) else {
        err(&ERROR_COULD_NOT_READ_VAR, [ArcStr::from(varname), file_msg.clone()])?;
        return Ok(None);
    };
    let (is_param, index) = {
        let info = &reader.allInfo[idx];
        (info.isParam, info.index)
    };
    if is_param {
        let absp = index.unsigned_abs() as usize;
        if absp == 0 || absp > reader.params.len() {
            err(&ERROR_COULD_NOT_READ_VAR, [ArcStr::from(varname), file_msg.clone()])?;
            return Ok(None);
        }
        let p = reader.params[absp - 1];
        Ok(Some(vec![if index < 0 { -p } else { p }; reader.nrows]))
    } else {
        match reader.read_vals(index) {
            Some(v) => Ok(Some(v)),
            None => {
                err(&ERROR_COULD_NOT_READ_VAR, [ArcStr::from(varname), file_msg.clone()])?;
                Ok(None)
            }
        }
    }
}

/// C `SimulationResultsImpl__readVarsFilterAliases`: for MATLAB4 the names
/// of all real (non-negated-alias) variables and parameters, one per storage
/// index, in `allInfo` order; the other formats fall through to
/// `readVars(readParameters=0, omcStyle=0)`.
fn read_vars_filter_aliases(reader: &ResultReader) -> Vec<ArcStr> {
    match reader {
        ResultReader::Mat(reader) => {
            let mut seen_param = std::collections::HashSet::new();
            let mut seen_var = std::collections::HashSet::new();
            let mut out = Vec::new();
            for info in reader.allInfo.iter().rev() {
                if info.index <= 0 {
                    continue; // negated aliases always have a real variable
                }
                let seen = if info.isParam { &mut seen_param } else { &mut seen_var };
                if !seen.insert(info.index) {
                    continue;
                }
                out.push(ArcStr::from(info.name.as_str()));
            }
            out.reverse();
            out
        }
        // Reverse document order — see readVariables.
        ResultReader::Plt(reader) => reader.variables().into_iter().rev().map(ArcStr::from).collect(),
        ResultReader::Csv(reader) => {
            reader.variables.iter().filter(|v| !v.is_empty()).map(|v| ArcStr::from(v.as_str())).collect()
        }
    }
}

/// C `getTimeVarName`: `"time"` unless only `"Time"` is present.
fn get_time_var_name(allvars: &[ArcStr]) -> &'static str {
    for v in allvars {
        if v == "time" {
            return "time";
        }
        if v == "Time" {
            return "Time";
        }
    }
    "time"
}

/// Strip `"` from a variable name (C does this into `var1` before lookups).
fn strip_quotes(var: &str) -> ArcStr {
    if var.contains('"') {
        ArcStr::from(var.replace('"', ""))
    } else {
        ArcStr::from(var)
    }
}

/// Count of leading equal timestamps (C `offset`/`offsetRef`): duplicated
/// initial points that get overwritten with the next value before comparing.
fn leading_dup_count(time: &[f64]) -> usize {
    let mut o = 0;
    while o + 1 < time.len() && time[o] == time[o + 1] {
        o += 1;
    }
    o
}

/// C `cmpData` for the `isResultCmp=1` path: compares one variable's trajectory
/// against the reference (event-aware, with reference interpolation), appends
/// differing points to `ddf`, and returns whether the variable differed.
fn cmp_data(
    varname: &ArcStr,
    time: &[f64],
    reftime: &[f64],
    data: &[f64],
    refdata: &[f64],
    reltol: f64,
    abstol: f64,
    ddf: &mut Vec<DiffData>,
) -> bool {
    let reftime_n = reftime.len() as isize;
    let data_n = data.len();
    let time_n = time.len();

    let mut average = 0.0;
    for &x in refdata {
        average += x.abs();
    }
    average /= refdata.len() as f64;
    average = reltol * average.abs() + abstol;

    let mut isdifferent = false;
    let mut j: isize = 0;
    let mut tr = reftime[0];
    let mut i: usize = 0;
    'outer: while i < data_n {
        let mut t = time[i];
        let d = data[i];
        let mut increased = false;
        while tr < t {
            if j + 1 < reftime_n {
                j += 1;
                tr = reftime[j as usize];
                increased = true;
                if tr == t {
                    break;
                }
            } else {
                break;
            }
        }
        if increased
            && (((t - tr) / tr).abs() > reltol
                || (t - tr).abs() > (t - reftime[(j - 1) as usize]).abs())
        {
            j -= 1;
            tr = reftime[j as usize];
        }

        // Events: at a discontinuity (two equal successive times) compare only
        // the left and right values of the event range.
        if i + 1 < time_n && almost_equal_default(t, time[i + 1]) {
            let d_left = d;
            if i + 1 < data_n {
                while almost_equal_default(t, time[i + 1]) {
                    i += 1;
                    if i + 1 >= data_n {
                        break;
                    }
                }
            }
            t = time[i];
            let d_right = data[i];

            // search event in reference forwards
            let mut refevent = false;
            let mut t_event = t + t * reltol * 0.1;
            if i < data_n {
                t_event = if t_event > time[i] { time[i] } else { t_event };
            } else {
                t_event = if t_event > time[i + 1] { time[i + 1] } else { t_event };
            }
            let j_event = j;
            let mut dr_left = 0.0;
            while tr < t_event {
                if j + 1 < reftime_n && almost_equal_default(tr, reftime[(j + 1) as usize]) {
                    dr_left = refdata[j as usize];
                    refevent = true;
                    loop {
                        j += 1;
                        if j + 1 >= reftime_n {
                            break;
                        }
                        if !almost_equal_default(tr, reftime[(j + 1) as usize]) {
                            break;
                        }
                    }
                }
                if !refevent {
                    j += 1;
                    if j >= reftime_n {
                        break;
                    }
                    tr = reftime[j as usize];
                } else {
                    tr = reftime[j as usize];
                    break;
                }
            }
            if refevent {
                tr = reftime[j as usize];
                let dr_right = refdata[j as usize];
                if (d_left - dr_left).abs() < average && (d_right - dr_right).abs() < average {
                    i += 1;
                    continue 'outer;
                }
            } else {
                // search event in reference backwards
                j = j_event;
                tr = reftime[j as usize];
                refevent = false;
                t_event = t - t * reltol * 0.1;
                let mut dr_right = 0.0;
                while tr > t_event {
                    if j > 1 && almost_equal_default(tr, reftime[(j - 1) as usize]) {
                        dr_right = refdata[j as usize];
                        refevent = true;
                        loop {
                            j -= 1;
                            if j <= 1 {
                                break;
                            }
                            if !almost_equal_default(tr, reftime[(j - 1) as usize]) {
                                break;
                            }
                        }
                    }
                    if !refevent {
                        j -= 1;
                        if j == 0 {
                            break;
                        }
                        tr = reftime[j as usize];
                    } else {
                        tr = reftime[j as usize];
                        break;
                    }
                }
                if refevent {
                    tr = reftime[j as usize];
                    dr_left = refdata[j as usize];
                    if (d_left - dr_left).abs() < average && (d_right - dr_right).abs() < average {
                        j = j_event;
                        tr = reftime[j as usize];
                        i += 1;
                        continue 'outer;
                    }
                }
                j = j_event;
                tr = reftime[j as usize];
            }
        }

        // Interpolate the reference to the result time when they don't coincide.
        let interpolate = (t - tr).abs() > 0.00001;
        let mut dr = refdata[j as usize];
        if interpolate {
            if tr > t {
                let mut jj = j;
                if j > 1 {
                    jj = j - 1;
                    if reftime[jj as usize] == tr {
                        loop {
                            jj -= 1;
                            if jj <= 0 {
                                break;
                            }
                            if reftime[jj as usize] != tr {
                                break;
                            }
                        }
                    }
                }
                if reftime[jj as usize] != tr {
                    dr = refdata[jj as usize]
                        + ((dr - refdata[jj as usize]) / (tr - reftime[jj as usize]))
                            * (t - reftime[jj as usize]);
                }
            } else {
                let mut jj = j;
                if j + 1 < reftime_n {
                    jj = j + 1;
                    if reftime[jj as usize] == tr {
                        loop {
                            jj += 1;
                            if jj >= reftime_n {
                                break;
                            }
                            if reftime[jj as usize] != tr {
                                break;
                            }
                        }
                    }
                }
                if reftime[jj as usize] != tr {
                    dr = dr
                        + ((refdata[jj as usize] - dr) / (reftime[jj as usize] - tr)) * (t - tr);
                }
            }
        }

        let mut err = (d - dr).abs();
        if err > average {
            if j + 1 < reftime_n && reftime[(j + 1) as usize] == tr {
                dr = refdata[(j + 1) as usize];
                err = (d - dr).abs();
            }
            if err < average {
                i += 1;
                continue 'outer;
            }
            isdifferent = true;
            ddf.push(DiffData {
                name: varname.clone(),
                data: d,
                dataref: dr,
                time: t,
                timeref: tr,
                interpolate,
            });
        }
        i += 1;
    }
    isdifferent
}

/// C `%.15g` rendering for the diff log file (delegates to the runtime's
/// printf-compatible float formatter).
fn g15(x: f64) -> String {
    openmodelica_util::System::sprintff(literal!("%.15g"), OrderedFloat(x))
        .map(|s| s.to_string())
        .unwrap_or_else(|_| format!("{x}"))
}

/// C `writeLogFile`: dump the differing data points as a semicolon-separated CSV.
fn write_log_file(
    filename: &str,
    ddf: &[DiffData],
    f: &str,
    reff: &str,
    reltol: f64,
    abstol: f64,
) -> std::io::Result<()> {
    use std::fmt::Write as _;
    let mut s = String::new();
    let _ = writeln!(s, "\"Generated by OpenModelica\";;;;;");
    let _ = writeln!(
        s,
        "\"Compared Files\";;;\"absolute tolerance\";{};relative tolerance;{}",
        g15(abstol),
        g15(reltol)
    );
    let _ = writeln!(s, "\"{f}\";;;;;;");
    let _ = writeln!(s, "\"{reff}\";;;;;;");
    let _ = writeln!(
        s,
        "\"Name\";\"Time\";\"DataPoint\";\"RefTime\";\"RefDataPoint\";\"absolute error\";\"relative error\";interpolate;"
    );
    for dd in ddf {
        let _ = writeln!(
            s,
            "{};{};{};{};{};{};{};{};",
            dd.name,
            g15(dd.time),
            g15(dd.data),
            g15(dd.timeref),
            g15(dd.dataref),
            g15((dd.data - dd.dataref).abs()),
            g15(((dd.data - dd.dataref) / dd.dataref).abs()),
            if dd.interpolate { '1' } else { '0' }
        );
    }
    openmodelica_wasi::fs::write(filename, s.as_bytes())
}

pub fn cmpSimulationResults(mut runningTestsuite: bool, mut filename: ArcStr, mut reffilename: ArcStr, mut logfilename: ArcStr, mut refTol: metamodelica::Real, mut absTol: metamodelica::Real, mut vars: Arc<metamodelica::List<ArcStr>>) -> Result<Arc<metamodelica::List<ArcStr>>> {
    // C: SimulationResults_cmpSimulationResults ->
    //    SimulationResultsCmp_compareResults(isResultCmp=1, isHtml=0).
    let reltol = refTol.into_inner();
    let abstol = absTol.into_inner();

    let mut reader_c = match ResultReader::open_reporting(&filename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_FILE, [filename.clone()])?;
            return Ok(Arc::new(List::Nil));
        }
    };
    let mut reader_ref = match ResultReader::open_reporting(&reffilename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_REFFILE, [reffilename.clone()])?;
            return Ok(Arc::new(List::Nil));
        }
    };

    let allvars = read_vars_filter_aliases(&reader_c);
    let allvarsref = read_vars_filter_aliases(&reader_ref);

    // Compare-list: the supplied vars, or every reference variable when empty.
    let mut cmpvars: Vec<ArcStr> = vars.as_ref().into_iter().cloned().collect();
    if cmpvars.is_empty() {
        cmpvars = allvarsref.clone();
        if cmpvars.is_empty() {
            err(&ERROR_GET_VARS, [])?;
            return Ok(Arc::new(List::Nil));
        }
    }

    let c_file = display_filename(runningTestsuite, &filename);
    let ref_file = display_filename(runningTestsuite, &reffilename);
    let time_name = get_time_var_name(&allvars);
    let timeref_name = get_time_var_name(&allvarsref);
    let time = match get_data(&mut reader_c, time_name, &c_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME, [])?;
            return Ok(Arc::new(List::Nil));
        }
    };
    let timeref = match get_data(&mut reader_ref, timeref_name, &ref_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME_REF, [])?;
            return Ok(Arc::new(List::Nil));
        }
    };

    // Warn (but continue) when the end times differ by more than the tolerance.
    let last = *time.last().unwrap();
    let last_ref = *timeref.last().unwrap();
    if (last - last_ref).abs() > reltol * last_ref.abs() {
        let buf = format!(
            "Resultfile and Reference have different end time points!\nReffile[{}]={}\nFile[{}]={}\n",
            timeref.len(),
            format_g(last_ref),
            time.len(),
            format_g(last)
        );
        Error::addMessage(
            ErrorTypes::Message {
                id: -1,
                ty: ErrorTypes::MessageType::SCRIPTING,
                severity: ErrorTypes::Severity::WARNING,
                message: ArcStr::from(buf),
            },
            Arc::new(List::Nil),
        )?;
    }

    let offset = leading_dup_count(&time);
    let offset_ref = leading_dup_count(&timeref);

    let mut ddf: Vec<DiffData> = Vec::new();
    let mut diff_vars: Vec<ArcStr> = Vec::new();
    let mut nfailed = 0u32;
    for var in &cmpvars {
        let var1 = strip_quotes(var.as_str());
        let mut dataref = match get_data(&mut reader_ref, var1.as_str(), &ref_file)? {
            Some(d) if !d.is_empty() => d,
            _ => {
                err(&ERROR_GET_DATA_FAILED, [var.clone(), ref_file.clone()])?;
                nfailed += 1;
                continue;
            }
        };
        let mut data = match get_data(&mut reader_c, var1.as_str(), &c_file)? {
            Some(d) if !d.is_empty() => d,
            _ => {
                err(&ERROR_GET_DATA_FAILED, [var.clone(), c_file.clone()])?;
                nfailed += 1;
                continue;
            }
        };
        // Adjust the duplicated initial data points (C shifts data[offset..0]).
        for j in (1..=offset).rev() {
            data[j - 1] = data[j];
        }
        for j in (1..=offset_ref).rev() {
            dataref[j - 1] = dataref[j];
        }
        if cmp_data(var, &time, &timeref, &data, &dataref, reltol, abstol, &mut ddf) {
            diff_vars.push(var.clone());
        }
    }

    if let Err(e) = write_log_file(logfilename.as_str(), &ddf, filename.as_str(), reffilename.as_str(), reltol, abstol) {
        let _ = e;
        Error::addMessage(
            ErrorTypes::Message {
                id: -1,
                ty: ErrorTypes::MessageType::SCRIPTING,
                severity: ErrorTypes::Severity::WARNING,
                message: literal!("Cannot write to the difference (.csv) file!\n"),
            },
            Arc::new(List::Nil),
        )?;
    }

    if !ddf.is_empty() || nfailed > 0 || !diff_vars.is_empty() {
        Error::addMessage(
            ErrorTypes::Message {
                id: -1,
                ty: ErrorTypes::MessageType::SCRIPTING,
                severity: ErrorTypes::Severity::WARNING,
                message: literal!("Files not Equal\n"),
            },
            Arc::new(List::Nil),
        )?;
        let mut items = vec![literal!("Files not Equal!")];
        items.extend(diff_vars.into_iter().rev());
        Ok(Arc::new(List::from_iter(items)))
    } else {
        Ok(Arc::new(List::from_iter([literal!("Files Equal!")])))
    }
}

/// Error norms for `deltaSimulationResults` (C `ErrorMethod`).
enum ErrorMethod {
    Norm1,
    Norm2,
    MaxErr,
}

/// C `deltaData`: accumulate the error norm of `data` vs `refdata` sampled at
/// the reference times (with linear interpolation of the result trajectory).
fn delta_data(method: &ErrorMethod, time: &[f64], reftime: &[f64], data: &[f64], refdata: &[f64]) -> f64 {
    let mut res0 = 0.0;
    let mut i = 0usize;
    let tn = time.len();
    // C uses `0.0001*time->data[time->n]` (one past the end) as the "coincides"
    // threshold; mirror the intended "largest time" with the last element.
    let thr = (0.0001 * time[tn - 1]).max(1e-12);
    for iref in 0..reftime.len() {
        let valref = refdata[iref];
        let t = reftime[iref];
        while i < tn && time[i] < t {
            i += 1;
        }
        if i >= tn {
            break;
        }
        let i2 = i + 1;
        let val = if (time[i] - t).abs() <= thr || i2 >= tn {
            data[i]
        } else {
            (data[i2] - data[i]) / (time[i2] - time[i]) * (t - time[i]) + data[i]
        };
        match method {
            ErrorMethod::Norm1 => res0 += (valref - val).abs(),
            ErrorMethod::Norm2 => res0 += (valref - val).powi(2),
            ErrorMethod::MaxErr => res0 = (valref - val).abs().max(res0),
        }
    }
    match method {
        ErrorMethod::Norm2 => res0.sqrt(),
        _ => res0,
    }
}

pub fn deltaSimulationResults(mut filename: ArcStr, mut reffilename: ArcStr, mut method: ArcStr, mut vars: Arc<metamodelica::List<ArcStr>>) -> Result<metamodelica::Real> {
    // C: SimulationResults_deltaSimulationResults -> SimulationResultsCmp_deltaResults.
    let errmethod = match method.as_str() {
        "1norm" => ErrorMethod::Norm1,
        "2norm" => ErrorMethod::Norm2,
        "maxerr" => ErrorMethod::MaxErr,
        _ => {
            Error::addMessage(
                ErrorTypes::Message {
                    id: -1,
                    ty: ErrorTypes::MessageType::SCRIPTING,
                    severity: ErrorTypes::Severity::WARNING,
                    message: literal!("Unknown method string: %s. 1-Norm is chosen."),
                },
                Arc::new(List::from_iter([method.clone()])),
            )?;
            ErrorMethod::Norm1
        }
    };

    let mut reader_c = match ResultReader::open_reporting(&filename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_FILE, [filename.clone()])?;
            return Ok(OrderedFloat(-1.0));
        }
    };
    let mut reader_ref = match ResultReader::open_reporting(&reffilename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_REFFILE, [filename.clone()])?;
            return Ok(OrderedFloat(-1.0));
        }
    };

    let allvars = read_vars_filter_aliases(&reader_c);
    let allvarsref = read_vars_filter_aliases(&reader_ref);
    let mut cmpvars: Vec<ArcStr> = vars.as_ref().into_iter().cloned().collect();
    if cmpvars.is_empty() {
        cmpvars = allvarsref.clone();
        if cmpvars.is_empty() {
            err(&ERROR_GET_VARS, [])?;
            return Ok(OrderedFloat(-1.0));
        }
    }

    // deltaSimulationResults is the C `deltaSimulationResults`, which passes
    // runningTestsuite = 0, so messages always use the full path.
    let c_file = filename.clone();
    let ref_file = reffilename.clone();
    let time_name = get_time_var_name(&allvars);
    let timeref_name = get_time_var_name(&allvarsref);
    let time = match get_data(&mut reader_c, time_name, &c_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME, [])?;
            return Ok(OrderedFloat(-1.0));
        }
    };
    let timeref = match get_data(&mut reader_ref, timeref_name, &ref_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME_REF, [])?;
            return Ok(OrderedFloat(-1.0));
        }
    };
    if time[0] > timeref[0] {
        err(&ERROR_FILE_STARTS_BEFORE, [])?;
        return Ok(OrderedFloat(-1.0));
    }
    if *time.last().unwrap() < *timeref.last().unwrap() {
        err(&ERROR_FILE_ENDS_BEFORE, [])?;
        return Ok(OrderedFloat(-1.0));
    }

    let offset = leading_dup_count(&time);
    let offset_ref = leading_dup_count(&timeref);
    let mut res = 0.0;
    for var in &cmpvars {
        let var1 = strip_quotes(var.as_str());
        let mut dataref = match get_data(&mut reader_ref, var1.as_str(), &ref_file)? {
            Some(d) if !d.is_empty() => d,
            _ => continue,
        };
        let mut data = match get_data(&mut reader_c, var1.as_str(), &c_file)? {
            Some(d) if !d.is_empty() => d,
            _ => continue,
        };
        for j in (1..=offset).rev() {
            data[j - 1] = data[j];
        }
        for j in (1..=offset_ref).rev() {
            dataref[j - 1] = dataref[j];
        }
        res += delta_data(&errmethod, &time, &timeref, &data, &dataref);
    }
    Ok(OrderedFloat(res))
}

// ---------------------------------------------------------------------------
// Tube-based comparison (port of SimulationResultsCmpTubes.c)
//
// `diffSimulationResults` builds a tolerance "tube" around the reference signal
// (the CSV-compare algorithm from ITI's Tubes.cs) and checks that the actual
// signal, resampled onto the reference timeline, stays inside it. The default
// `rangeDelta` is non-zero, so the full `calculateTubes` geometry runs.
// ---------------------------------------------------------------------------

/// Port of the `privates` tube state in SimulationResultsCmpTubes.c.
struct Tubes {
    mh: Vec<f64>,
    ml: Vec<f64>,
    x_high: Vec<f64>,
    x_low: Vec<f64>,
    y_high: Vec<f64>,
    y_low: Vec<f64>,
    i0h: Vec<i64>,
    i1h: Vec<i64>,
    i0l: Vec<i64>,
    i1l: Vec<i64>,
    t_start: f64,
    t_stop: f64,
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
    current_slope: f64,
    slope_dif: f64,
    delta: f64,
    s: f64,
    x_rel_eps: f64,
    x_min_step: f64,
    min: f64,
    max: f64,
    count_low: usize,
    count_high: usize,
    length: usize,
}

impl Tubes {
    /// C `generateHighTube`.
    fn generate_high_tube(&mut self, x: &[f64], y: &[f64]) {
        let mut index = self.count_high as isize - 1;
        let m1 = self.mh[index as usize];
        let mut m2 = self.mh[(index - 1) as usize];
        self.slope_dif = (m1 - m2).abs();

        if self.slope_dif == 0.0
            || (self.slope_dif < 2e-15 * m1.abs().max(m2.abs())
                && self.i0h[self.count_high - 1] - self.i1h[self.count_high - 2] < 100)
        {
            self.i0h[(index - 1) as usize] = self.i0h[index as usize];
            self.count_high -= 1;
            let x3 = x[self.i0h[(index - 1) as usize] as usize];
            let y3 = y[self.i0h[(index - 1) as usize] as usize];
            let x4 = x[self.i1h[(index - 1) as usize] as usize];
            let y4 = y[self.i1h[(index - 1) as usize] as usize];
            self.mh[(index - 1) as usize] = (y3 - y4) / (x3 - x4);
        } else {
            self.x_high[index as usize] = self.x2
                - (self.delta * (m1 + m2)
                    / ((m2 * m2 + self.s * self.s).sqrt() + (m1 * m1 + self.s * self.s).sqrt()));
            if m1 * m2 < 0.0 {
                self.y_high[index as usize] = self.y2
                    + (self.delta
                        * (m1 * (m2 * m2 + self.s * self.s).sqrt()
                            - m2 * (m1 * m1 + self.s * self.s).sqrt()))
                        / (m1 - m2);
            } else {
                self.y_high[index as usize] = self.y2
                    + (self.s * self.s * self.delta * (m1 + m2)
                        / (m1 * (m2 * m2 + self.s * self.s).sqrt()
                            + m2 * (m1 * m1 + self.s * self.s).sqrt()));
            }

            if self.x_high[index as usize] == self.x_high[(index - 1) as usize]
                && self.y_high[index as usize] != self.y_high[(index - 1) as usize]
            {
                self.x_high[index as usize] = self.x_high[(index - 1) as usize] + self.x_min_step;
                self.y_high[index as usize] = self.y2
                    + m1 * (self.x_high[index as usize] - self.x2)
                    + self.delta * (m1 * m1 + self.s * self.s).sqrt();
                self.mh[(index - 1) as usize] =
                    (self.y_high[index as usize] - self.y_high[(index - 1) as usize]) / self.x_min_step;
            }

            while index > 1 && self.x_high[index as usize] <= self.x_high[(index - 1) as usize] {
                self.i0h[(index - 1) as usize] = self.i0h[index as usize];
                self.i1h[(index - 1) as usize] = self.i1h[index as usize];
                self.mh[(index - 1) as usize] = self.mh[index as usize];
                index -= 1;
                self.count_high -= 1;

                if index == 0 {
                    let x3 = x[0];
                    self.x_high[index as usize] = x3 - self.delta;
                    self.y_high[index as usize] = self.y2
                        + m1 * (self.x_high[index as usize] - self.x2)
                        + self.delta * (m1 * m1 + self.s * self.s).sqrt();
                } else {
                    let x3 = self.x_high[(index - 1) as usize];
                    let y3 = self.y_high[(index - 1) as usize];
                    m2 = self.mh[(index - 1) as usize];
                    self.x_high[index as usize] = (m2 * x3 - m1 * self.x2 + self.y2 - y3
                        + self.delta * (m1 * m1 + self.s * self.s).sqrt())
                        / (m2 - m1);
                    self.y_high[index as usize] = (m2 * m1 * (x3 - self.x2)
                        + m2 * (self.y2 + self.delta * (m1 * m1 + self.s * self.s).sqrt())
                        - m1 * y3)
                        / (m2 - m1);
                }
            }
        }
    }

    /// C `generateLowTube`.
    fn generate_low_tube(&mut self, x: &[f64], y: &[f64]) {
        let mut index = self.count_low as isize - 1;
        let m1 = self.ml[index as usize];
        let mut m2 = self.ml[(index - 1) as usize];
        self.slope_dif = (m1 - m2).abs();

        if self.slope_dif == 0.0
            || (self.slope_dif < 2e-15 * m1.abs().max(m2.abs())
                && self.i0l[self.count_low - 1] - self.i1l[self.count_low - 2] < 100)
        {
            self.i0l[(index - 1) as usize] = self.i0l[index as usize];
            self.count_low -= 1;
            let x3 = x[self.i0l[(index - 1) as usize] as usize];
            let y3 = y[self.i0l[(index - 1) as usize] as usize];
            let x4 = x[self.i1l[(index - 1) as usize] as usize];
            let y4 = y[self.i1l[(index - 1) as usize] as usize];
            self.ml[(index - 1) as usize] = (y3 - y4) / (x3 - x4);
        } else {
            self.x_low[index as usize] = self.x2
                + (self.delta * (m1 + m2)
                    / ((m2 * m2 + self.s * self.s).sqrt() + (m1 * m1 + self.s * self.s).sqrt()));
            if m1 * m2 < 0.0 {
                self.y_low[index as usize] = self.y2
                    - (self.delta
                        * (m1 * (m2 * m2 + self.s * self.s).sqrt()
                            - m2 * (m1 * m1 + self.s * self.s).sqrt()))
                        / (m1 - m2);
            } else {
                self.y_low[index as usize] = self.y2
                    - (self.s * self.s * self.delta * (m1 + m2)
                        / (m1 * (m2 * m2 + self.s * self.s).sqrt()
                            + m2 * (m1 * m1 + self.s * self.s).sqrt()));
            }

            if self.x_low[index as usize] == self.x_low[(index - 1) as usize]
                && self.y_low[index as usize] != self.y_low[(index - 1) as usize]
            {
                self.x_low[index as usize] = self.x_low[(index - 1) as usize] + self.x_min_step;
                self.y_low[index as usize] = self.y2
                    + m1 * (self.x_low[index as usize] - self.x2)
                    - self.delta * (m1 * m1 + self.s * self.s).sqrt();
                self.ml[(index - 1) as usize] =
                    (self.y_low[index as usize] - self.y_low[(index - 1) as usize]) / self.x_min_step;
            }

            while index > 1 && self.x_low[index as usize] <= self.x_low[(index - 1) as usize] {
                self.i0l[(index - 1) as usize] = self.i0l[index as usize];
                self.i1l[(index - 1) as usize] = self.i1l[index as usize];
                self.ml[(index - 1) as usize] = self.ml[index as usize];
                index -= 1;
                self.count_low -= 1;

                if index == 0 {
                    let x3 = x[0];
                    self.x_low[index as usize] = x3 - self.delta;
                    self.y_low[index as usize] = self.y2
                        + m1 * (self.x_low[index as usize] - self.x2)
                        - self.delta * (m1 * m1 + self.s * self.s).sqrt();
                } else {
                    let x3 = self.x_low[(index - 1) as usize];
                    let y3 = self.y_low[(index - 1) as usize];
                    m2 = self.ml[(index - 1) as usize];
                    self.x_low[index as usize] = (m2 * x3 - m1 * self.x2 + self.y2 - y3
                        - self.delta * (m1 * m1 + self.s * self.s).sqrt())
                        / (m2 - m1);
                    self.y_low[index as usize] = (m2 * m1 * (x3 - self.x2)
                        + m2 * (self.y2 - self.delta * (m1 * m1 + self.s * self.s).sqrt())
                        - m1 * y3)
                        / (m2 - m1);
                }
            }
        }
    }
}

/// C `calculateTubes`: build the upper/lower tolerance tube around `(x,y)`.
/// `x` (the reference timeline) is adjusted in place to keep it strictly
/// increasing, exactly as the C code mutates `ref.time`.
fn calculate_tubes(x: &mut [f64], y: &[f64], length: usize, r: f64) -> Tubes {
    let cap = length + 1;
    let mut p = Tubes {
        mh: vec![0.0; cap],
        ml: vec![0.0; cap],
        x_high: vec![0.0; cap],
        x_low: vec![0.0; cap],
        y_high: vec![0.0; cap],
        y_low: vec![0.0; cap],
        i0h: vec![0; cap],
        i1h: vec![0; cap],
        i0l: vec![0; cap],
        i1l: vec![0; cap],
        t_start: x[0],
        t_stop: x[length - 1],
        x1: 0.0,
        y1: 0.0,
        x2: 0.0,
        y2: 0.0,
        current_slope: 0.0,
        slope_dif: 0.0,
        delta: 0.0,
        s: 0.0,
        x_rel_eps: 1e-15,
        x_min_step: 0.0,
        min: y[0],
        max: y[0],
        count_low: 0,
        count_high: 0,
        length,
    };
    p.x_min_step = ((p.t_stop - p.t_start) + p.t_start.abs()) * p.x_rel_eps;
    p.delta = r * (p.t_stop - p.t_start);

    for i in 1..length {
        p.max = y[i].max(p.max);
        p.min = y[i].min(p.min);
    }
    p.s = (4.0 * (p.max - p.min) / (p.t_stop - p.t_start).abs()).abs();
    if p.s < 0.0004 / (p.t_stop - p.t_start).abs() {
        p.s = 0.0004 / (p.t_stop - p.t_start).abs();
    }

    for i in 1..length {
        p.x1 = x[i];
        p.y1 = y[i];
        p.x2 = x[i - 1];
        p.y2 = y[i - 1];
        // catch jumps
        if p.x1 <= p.x2 && p.y1 == p.y2 && p.count_high == 0 {
            continue;
        }
        if p.x1 <= p.x2 && p.y1 == p.y2 {
            p.x1 = p.x1.max(x[p.i1l[p.count_low - 1] as usize] + p.x_min_step);
            p.x1 = p.x1.max(x[p.i1h[p.count_high - 1] as usize] + p.x_min_step);
            x[i] = p.x1;
            p.current_slope = p.mh[p.count_high - 1];
        } else {
            if p.x1 <= p.x2 {
                p.x1 = p.x2 + p.x_min_step;
                x[i] = p.x1;
            }
            p.current_slope = (p.y1 - p.y2) / (p.x1 - p.x2);
        }

        p.i0h[p.count_high] = i as i64;
        p.i1h[p.count_high] = (i - 1) as i64;
        p.mh[p.count_high] = p.current_slope;

        p.i0l[p.count_low] = i as i64;
        p.i1l[p.count_low] = (i - 1) as i64;
        if p.x1 <= p.x2 && p.y1 == p.y2 {
            p.current_slope = p.ml[p.count_low - 1];
        }
        p.ml[p.count_low] = p.current_slope;

        if p.count_high == 0 {
            p.x_high[p.count_high] = p.x2 - p.delta;
            p.y_high[p.count_high] = p.y2 - p.current_slope * p.delta
                + p.delta * (p.current_slope * p.current_slope + p.s * p.s).sqrt();
            p.x_low[p.count_low] = p.x2 - p.delta;
            p.y_low[p.count_low] = p.y2 - p.current_slope * p.delta
                - p.delta * (p.current_slope * p.current_slope + p.s * p.s).sqrt();
            p.count_high += 1;
            p.count_low += 1;
        } else {
            p.x_high[p.count_high] = 1.0;
            p.y_high[p.count_high] = 1.0;
            p.x_low[p.count_low] = 1.0;
            p.y_low[p.count_low] = 1.0;
            p.count_high += 1;
            p.count_low += 1;
            p.generate_high_tube(x, y);
            p.generate_low_tube(x, y);
        }
    }

    // Degenerate series — a single sample, or time that never advances (a
    // start == stop run like the ModelicaTest function tests with
    // stopTime=0.0 produces the time column {0.0, 0.0}): every iteration
    // above took the jump-continue, no segment was created, and the
    // terminal extension below would index count-1 with count == 0 (the C
    // original, SimulationResultsCmpTubes.c, reads out of bounds here).
    // Seed a flat zero-slope tube at the first sample instead; the relative
    // tolerance the caller adds then makes the comparison pointwise.
    if p.count_high == 0 {
        p.mh[0] = 0.0;
        p.ml[0] = 0.0;
        p.x_high[0] = x[0] - p.delta;
        p.y_high[0] = y[0];
        p.x_low[0] = x[0] - p.delta;
        p.y_low[0] = y[0];
        p.count_high = 1;
        p.count_low = 1;
    }

    // terminal value, upper tube
    p.x1 = p.x_high[p.count_high - 1];
    p.y1 = p.y_high[p.count_high - 1];
    p.x2 = p.t_stop;
    p.current_slope = p.mh[p.count_high - 1];
    p.x_high[p.count_high] = p.x2 + p.delta;
    p.y_high[p.count_high] = p.y1 + p.current_slope * (p.x2 + p.delta - p.x1);
    p.count_high += 1;

    // terminal value, lower tube
    p.x1 = p.x_low[p.count_low - 1];
    p.y1 = p.y_low[p.count_low - 1];
    p.x2 = p.t_stop;
    p.current_slope = p.ml[p.count_low - 1];
    p.x_low[p.count_low] = p.x2 + p.delta;
    p.y_low[p.count_low] = p.y1 + p.current_slope * (p.x2 + p.delta - p.x1);
    p.count_low += 1;

    p
}

/// C `linearInterpolation` (with the x-abs-tol NaN guards).
fn linear_interpolation(x: f64, x0: f64, x1: f64, y0: f64, y1: f64, xabstol: f64) -> f64 {
    if almost_equal_rel_abs(x0, x, 0.0, xabstol) {
        y0
    } else if almost_equal_rel_abs(x1, x, 0.0, xabstol) {
        y1
    } else if almost_equal_rel_abs(x1, x0, 0.0, xabstol) {
        y0
    } else {
        y0 + ((y1 - y0) / (x1 - x0)) * (x - x0)
    }
}

/// C `calibrateValues`: resample `(target_time, target_values)` onto the
/// `source_time` timeline. `nsource` may be shrunk to avoid extrapolation.
fn calibrate_values(
    source_time: &[f64],
    target_time: &[f64],
    target_values: &[f64],
    nsource: &mut usize,
    ntarget: usize,
    xabstol: f64,
) -> Vec<f64> {
    let n = *nsource;
    let mut out = vec![0.0; n];
    let (mut x0, mut x1, mut y0, mut y1) = (0.0, 0.0, 0.0, 0.0);
    let mut j = 1usize;
    for i in 0..n {
        let x = source_time[i];
        if target_time[j] > source_time[n - 1] && target_time[j - 1] > source_time[n - 1] {
            out[i] = linear_interpolation(x, x0, x1, y0, y1, xabstol);
            *nsource = i + 1;
            break;
        }
        x1 = target_time[j];
        y1 = target_values[j];
        while x1 <= x && (j + 1) < ntarget {
            j += 1;
            x1 = target_time[j];
            y1 = target_values[j];
            if almost_equal_rel_abs(x1, x, 0.0, xabstol) {
                break;
            }
        }
        x0 = target_time[j - 1];
        y0 = target_values[j - 1];
        if i > 0
            && almost_equal_rel_abs(source_time[i - 1], x0, 0.0, xabstol)
            && almost_equal_rel_abs(x0, x1, 0.0, xabstol)
        {
            out[i] = y1;
        } else {
            out[i] = linear_interpolation(x, x0, x1, y0, y1, xabstol);
        }
    }
    out
}

/// C `addRelativeTolerance`: widen the tube by a relative+absolute margin.
fn add_relative_tolerance(target: &mut [f64], source: &[f64], length: usize, reltol: f64, abstol: f64, direction: i32) {
    if direction > 0 {
        for i in 0..length {
            target[i] = (source[i] + (source[i] * reltol).abs().max(abstol)).max(target[i]);
        }
    } else {
        for i in 0..length {
            target[i] = (source[i] - (source[i] * reltol).abs().max(abstol)).min(target[i]);
        }
    }
}

/// C `validate`: returns the per-point error vector if the actual signal leaves
/// the tube anywhere, or `None` when it stays inside. Adjusts `low`/`high` at
/// event points (as the C code does in place).
fn validate(
    n: usize,
    ref_time: &[f64],
    ref_values: &[f64],
    low: &mut [f64],
    high: &mut [f64],
    calibrated_values: &[f64],
    reltol: f64,
    abstol: f64,
    xabstol: f64,
) -> Option<Vec<f64>> {
    let mut error = vec![0.0; n];
    let mut isdifferent = 0u32;
    let mut last_step_error = true;
    for i in 0..n {
        let mut this_step_error = false;
        let is_event = (i > 0 && almost_equal_rel_abs(ref_time[i], ref_time[i - 1], 0.0, xabstol))
            || (i + 1 < n && almost_equal_rel_abs(ref_time[i], ref_time[i + 1], 0.0, xabstol));
        if is_event {
            let refv = ref_values[i];
            let val = calibrated_values[i];
            let tol = (abstol * 10.0).max(refv.abs().max(val.abs()) * reltol * 10.0);
            high[i] = (if last_step_error { refv } else { refv.max(val) }) + tol;
            low[i] = (if last_step_error { refv } else { refv.min(val) }) - tol;
            error[i] = f64::NAN;
        } else {
            error[i] = 0.0;
            this_step_error = last_step_error;
            if calibrated_values[i] < low[i] {
                error[i] = low[i] - calibrated_values[i];
                isdifferent += 1;
                this_step_error = true;
            } else if calibrated_values[i] > high[i] {
                error[i] = calibrated_values[i] - high[i];
                isdifferent += 1;
                this_step_error = true;
            }
        }
        last_step_error = this_step_error;
    }
    if isdifferent > 0 {
        Some(error)
    } else {
        None
    }
}

/// C `cmpDataTubes` for the `isResultCmp=0` path: returns whether the variable
/// differs (left the reference tube). `time`/`data` are the actual trajectory,
/// `reftime`/`refdata` the reference (mutated in place by the tube construction,
/// as in the C code). When `html_out` is `Some`, the dygraph HTML report is
/// appended to it (the `isHtml=1` branch, used by `diffSimulationResultsHtml`).
#[allow(clippy::too_many_arguments)]
fn cmp_data_tubes(
    time: &[f64],
    reftime: &mut [f64],
    refdata: &[f64],
    data: &[f64],
    reltol: f64,
    range_delta: f64,
    reltol_diff_max_min: f64,
    var_name: &str,
    html_out: Option<&mut String>,
) -> bool {
    let with_tubes = range_delta == 0.0;
    let ref_size = reftime.len();
    let xabstol = (reftime[ref_size - 1] - reftime[0])
        * (if with_tubes { range_delta } else { 1e-3 })
        / (time.len().max(ref_size) as f64);

    // Only the (default) non-zero rangeDelta path is exercised; build the tube.
    let priv_ = calculate_tubes(reftime, refdata, ref_size, range_delta);

    let mut n = ref_size;
    let calibrated_values =
        calibrate_values(reftime, time, data, &mut n, time.len(), xabstol);
    let mut high = calibrate_values(reftime, &priv_.x_high, &priv_.y_high, &mut n, priv_.count_high, xabstol);
    let mut low = calibrate_values(reftime, &priv_.x_low, &priv_.y_low, &mut n, priv_.count_low, xabstol);

    let abstol = if priv_.max - priv_.min == 0.0 && priv_.max < reltol_diff_max_min * reltol_diff_max_min {
        reltol_diff_max_min * reltol_diff_max_min
    } else {
        ((priv_.max - priv_.min) * reltol_diff_max_min).abs()
    };
    add_relative_tolerance(&mut high, refdata, n, reltol, abstol, 1);
    add_relative_tolerance(&mut low, refdata, n, reltol, abstol, -1);

    let error = validate(n, reftime, refdata, &mut low, &mut high, &calibrated_values, reltol, abstol, xabstol);

    if let Some(html) = html_out {
        write_tube_html(
            html, var_name, time, reftime, refdata, data, &calibrated_values,
            &high, &low, error.as_deref(), n, reltol, abstol, reltol_diff_max_min, range_delta,
        );
    }

    error.is_some()
}

/// Build the dygraph HTML report for one variable, mirroring the `isHtml=1`
/// output of C `cmpDataTubes` (SimulationResultsCmpTubes.c): a `<html>` page
/// embedding a Dygraph fed an array of `[time,reference,actual,high,low,error,
/// actual(original)]` rows. `error` is `None` when the variable stayed inside
/// the tube (the error column is then `null` everywhere).
#[allow(clippy::too_many_arguments)]
fn write_tube_html(
    html: &mut String,
    var_name: &str,
    time: &[f64],
    reftime: &[f64],
    refdata: &[f64],
    data: &[f64],
    calibrated_values: &[f64],
    high: &[f64],
    low: &[f64],
    error: Option<&[f64]>,
    n: usize,
    reltol: f64,
    abstol: f64,
    reltol_diff_max_min: f64,
    range_delta: f64,
) {
    let ref_size = reftime.len();
    // `concat!` preserves the exact leading whitespace of each line (the CSS
    // block is indented); a `\`-continued string literal would strip it.
    html.push_str(concat!(
        "<html>\n",
        "<head>\n",
        "<script type=\"text/javascript\" src=\"dygraph-combined.js\"></script>\n",
        "    <style type=\"text/css\">\n",
        "    #graphdiv {\n",
        "      position: absolute;\n",
        "      left: 10px;\n",
        "      right: 10px;\n",
        "      top: 40px;\n",
        "      bottom: 10px;\n",
        "    }\n",
        "    </style>\n",
        "</head>\n",
        "<body>\n",
        "<div id=\"graphdiv\"></div>\n",
        "<p><input type=checkbox id=\"0\" checked onClick=\"change(this)\">\n",
        "<label for=\"0\">reference</label>\n",
        "<input type=checkbox id=\"1\" checked onClick=\"change(this)\">\n",
        "<label for=\"1\">actual</label>\n",
        "<input type=checkbox id=\"2\" checked onClick=\"change(this)\">\n",
        "<label for=\"2\">high</label>\n",
        "<input type=checkbox id=\"3\" checked onClick=\"change(this)\">\n",
        "<label for=\"3\">low</label>\n",
        "<input type=checkbox id=\"4\" checked onClick=\"change(this)\">\n",
        "<label for=\"4\">error</label>\n",
        "<input type=checkbox id=\"5\" onClick=\"change(this)\">\n",
        "<label for=\"5\">actual (original)</label>\n",
    ));
    html.push_str(&format!(
        "Reference time: {} to {}, actual time: {} to {}. Parameters used for the comparison: \
Relative tolerance {}. Absolute tolerance {} ({} relative). Range delta {}.",
        format_g_prec15(reftime[0]),
        format_g_prec15(reftime[ref_size - 1]),
        format_g_prec15(time[0]),
        format_g_prec15(time[time.len() - 1]),
        format_g_prec(reltol, 2),
        format_g_prec(abstol, 2),
        format_g_prec(reltol_diff_max_min, 2),
        format_g_prec(range_delta, 2),
    ));
    html.push_str(
        "</p>\n\
<script type=\"text/javascript\">\n\
g = new Dygraph(document.getElementById(\"graphdiv\"),\n\
[\n",
    );

    let mut j = 0usize;
    for i in 0..ref_size {
        html.push_str(&format!("[{},{},", format_g_prec15(reftime[i]), format_g_prec15(refdata[i])));
        if i < n {
            match error {
                Some(e) if !e[i].is_nan() => html.push_str(&format!(
                    "{},{},{},{}",
                    format_g_prec15(calibrated_values[i]), format_g_prec15(high[i]), format_g_prec15(low[i]), format_g_prec15(e[i])
                )),
                _ => html.push_str(&format!(
                    "{},{},{},null",
                    format_g_prec15(calibrated_values[i]), format_g_prec15(high[i]), format_g_prec15(low[i])
                )),
            }
            if j < data.len() && reftime[i] == time[j] {
                html.push_str(&format!(",{}],\n", format_g_prec15(data[j])));
                j += 1;
            } else {
                html.push_str(",null],\n");
            }
        } else {
            html.push_str("null,null,null,null,null],\n");
        }
        while j < data.len() && reftime[i] > time[j] {
            html.push_str(&format!(
                "[{},null,null,null,null,null,{}],\n",
                format_g_prec15(time[j]), format_g_prec15(data[j])
            ));
            j += 1;
        }
    }
    html.push_str("],\n");
    html.push_str(&format!(
        "{{title: '{var_name}',\n\
legend: 'always',\n\
xlabel: ['time'],\n\
connectSeparatedPoints: true,\n\
labels: ['time','reference','actual','high','low','error','actual (original)'],\n\
y2label: ['error'],\n\
series : {{ 'error': {{ axis: 'y2' }} }},\n\
colors: ['blue','red','teal','lightblue','orange','black'],\n\
visibility: [true,true,true,true,true,false]\n\
}});\n\
function change(el) {{\n  g.setVisibility(parseInt(el.id), el.checked);\n\
}}\n\
</script>\n\
</body>\n\
</html>\n"
    ));
}

pub fn diffSimulationResults(mut runningTestsuite: bool, mut filename: ArcStr, mut reffilename: ArcStr, mut prefix: ArcStr, mut refTol: metamodelica::Real, mut relTolDiffMaxMin: metamodelica::Real, mut rangeDelta: metamodelica::Real, mut vars: Arc<metamodelica::List<ArcStr>>, mut keepEqualResults: bool) -> Result<(bool, Arc<metamodelica::List<ArcStr>>)> {
    // C: SimulationResults_diffSimulationResults ->
    //    SimulationResultsCmp_compareResults(isResultCmp=0, isHtml=0).
    let reltol = refTol.into_inner();
    let reltol_diff_max_min = relTolDiffMaxMin.into_inner();
    let range_delta = rangeDelta.into_inner();

    let mut reader_c = match ResultReader::open_reporting(&filename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_FILE, [filename.clone()])?;
            return Ok((false, Arc::new(List::Nil)));
        }
    };
    let mut reader_ref = match ResultReader::open_reporting(&reffilename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_REFFILE, [reffilename.clone()])?;
            return Ok((false, Arc::new(List::Nil)));
        }
    };

    let allvars = read_vars_filter_aliases(&reader_c);
    let allvarsref = read_vars_filter_aliases(&reader_ref);
    let mut cmpvars: Vec<ArcStr> = vars.as_ref().into_iter().cloned().collect();
    if cmpvars.is_empty() {
        cmpvars = allvarsref.clone();
        if cmpvars.is_empty() {
            err(&ERROR_GET_VARS, [])?;
            return Ok((false, Arc::new(List::Nil)));
        }
    }

    let c_file = display_filename(runningTestsuite, &filename);
    let ref_file = display_filename(runningTestsuite, &reffilename);
    let time_name = get_time_var_name(&allvars);
    let timeref_name = get_time_var_name(&allvarsref);
    let time = match get_data(&mut reader_c, time_name, &c_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME, [])?;
            return Ok((false, Arc::new(List::Nil)));
        }
    };
    let timeref = match get_data(&mut reader_ref, timeref_name, &ref_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME_REF, [])?;
            return Ok((false, Arc::new(List::Nil)));
        }
    };

    // Warn (but continue) when the end times differ by more than the tolerance.
    let last = *time.last().unwrap();
    let last_ref = *timeref.last().unwrap();
    if (last - last_ref).abs() > reltol * last_ref.abs() {
        let buf = format!(
            "Resultfile and Reference have different end time points!\nReffile[{}]={}\nFile[{}]={}\n",
            timeref.len(),
            format_g(last_ref),
            time.len(),
            format_g(last)
        );
        Error::addMessage(
            ErrorTypes::Message {
                id: -1,
                ty: ErrorTypes::MessageType::SCRIPTING,
                severity: ErrorTypes::Severity::WARNING,
                message: ArcStr::from(buf),
            },
            Arc::new(List::Nil),
        )?;
    }

    let offset = leading_dup_count(&time);
    let offset_ref = leading_dup_count(&timeref);

    let mut diff_vars: Vec<ArcStr> = Vec::new();
    for var in &cmpvars {
        let var1 = strip_quotes(var.as_str());
        let mut dataref = match get_data(&mut reader_ref, var1.as_str(), &ref_file)? {
            Some(d) if !d.is_empty() => d,
            _ => {
                err(&ERROR_GET_DATA_FAILED, [var.clone(), ref_file.clone()])?;
                continue;
            }
        };
        let mut data = match get_data(&mut reader_c, var1.as_str(), &c_file)? {
            Some(d) if !d.is_empty() => d,
            _ => {
                err(&ERROR_GET_DATA_FAILED, [var.clone(), c_file.clone()])?;
                continue;
            }
        };
        for j in (1..=offset).rev() {
            data[j - 1] = data[j];
        }
        for j in (1..=offset_ref).rev() {
            dataref[j - 1] = dataref[j];
        }
        // cmp_data_tubes mutates the reference timeline; give it a private copy
        // so each variable's comparison sees the unmodified timeline.
        let mut timeref_work = timeref.clone();
        if cmp_data_tubes(&time, &mut timeref_work, &dataref, &data, reltol, range_delta, reltol_diff_max_min, var1.as_str(), None) {
            // C prepends to the diff list (reverse processing order).
            diff_vars.insert(0, var.clone());
        }
    }

    let success = diff_vars.is_empty();
    Ok((success, Arc::new(List::from_iter(diff_vars))))
}

pub fn diffSimulationResultsHtml(mut runningTestsuite: bool, mut filename: ArcStr, mut reffilename: ArcStr, mut refTol: metamodelica::Real, mut relTolDiffMaxMin: metamodelica::Real, mut rangeDelta: metamodelica::Real, mut var: ArcStr) -> Result<ArcStr> {
    // C: SimulationResults_diffSimulationResultsHtml ->
    //    SimulationResultsCmp_compareResults(isResultCmp=0, isHtml=1) on a single
    //    variable, returning the dygraph HTML page (or "" on failure).
    let reltol = refTol.into_inner();
    let reltol_diff_max_min = relTolDiffMaxMin.into_inner();
    let range_delta = rangeDelta.into_inner();

    let mut reader_c = match ResultReader::open_reporting(&filename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_FILE, [filename.clone()])?;
            return Ok(ArcStr::from(""));
        }
    };
    let mut reader_ref = match ResultReader::open_reporting(&reffilename)? {
        Some(r) => r,
        None => {
            err(&ERROR_OPEN_REFFILE, [reffilename.clone()])?;
            return Ok(ArcStr::from(""));
        }
    };

    let allvars = read_vars_filter_aliases(&reader_c);
    let allvarsref = read_vars_filter_aliases(&reader_ref);

    let c_file = display_filename(runningTestsuite, &filename);
    let ref_file = display_filename(runningTestsuite, &reffilename);
    let time_name = get_time_var_name(&allvars);
    let timeref_name = get_time_var_name(&allvarsref);
    let time = match get_data(&mut reader_c, time_name, &c_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME, [])?;
            return Ok(ArcStr::from(""));
        }
    };
    let timeref = match get_data(&mut reader_ref, timeref_name, &ref_file)? {
        Some(t) if !t.is_empty() => t,
        _ => {
            err(&ERROR_GET_TIME_REF, [])?;
            return Ok(ArcStr::from(""));
        }
    };

    let offset = leading_dup_count(&time);
    let offset_ref = leading_dup_count(&timeref);

    let var1 = strip_quotes(var.as_str());
    let mut dataref = match get_data(&mut reader_ref, var1.as_str(), &ref_file)? {
        Some(d) if !d.is_empty() => d,
        _ => {
            err(&ERROR_GET_DATA_FAILED, [var.clone(), ref_file.clone()])?;
            return Ok(ArcStr::from(""));
        }
    };
    let mut data = match get_data(&mut reader_c, var1.as_str(), &c_file)? {
        Some(d) if !d.is_empty() => d,
        _ => {
            err(&ERROR_GET_DATA_FAILED, [var.clone(), c_file.clone()])?;
            return Ok(ArcStr::from(""));
        }
    };
    for j in (1..=offset).rev() {
        data[j - 1] = data[j];
    }
    for j in (1..=offset_ref).rev() {
        dataref[j - 1] = dataref[j];
    }

    let mut timeref_work = timeref.clone();
    let mut html = String::new();
    cmp_data_tubes(
        &time, &mut timeref_work, &dataref, &data, reltol, range_delta,
        reltol_diff_max_min, var1.as_str(), Some(&mut html),
    );
    Ok(ArcStr::from(html))
}

/// Metadata copied out of the reader for each requested variable, decoupling
/// the (immutable) `allInfo` lookup from the later mutable trajectory reads.
struct FilterVar {
    name: String,
    descr: String,
    isParam: bool,
    /// 1-based data_1 (param) / data_2 (var) index in the *input* file; the sign
    /// selects the negated alias.
    index: i32,
}

/// Append a MATLAB v4 matrix header (mirrors `writeMatVer4MatrixHeader`). The
/// host is little-endian (the only build target), so the type's 1000s digit is
/// 0; `elem_size` selects the element type: 1 = char (51), 4 = int32 (20),
/// 8 = double (0).
fn push_mat_header(out: &mut Vec<u8>, name: &str, rows: u32, cols: u32, elem_size: u32) {
    let ty: u32 = match elem_size {
        1 => 51,
        4 => 20,
        _ => 0,
    };
    let namelen = name.len() as u32 + 1;
    for field in [ty, rows, cols, 0u32, namelen] {
        out.extend_from_slice(&field.to_le_bytes());
    }
    out.extend_from_slice(name.as_bytes());
    out.push(0); // NUL terminator (namelen counts it)
}

/// Append a fixed-width char matrix (`name`/`description`): `rows` strings each
/// padded to `width` bytes, stored column-major (`buf[width*j..]` holds char `j`
/// of every row) exactly like the C filter's transposed buffer.
fn push_char_matrix(out: &mut Vec<u8>, name: &str, strings: &[&str], width: usize) {
    push_mat_header(out, name, strings.len() as u32, width as u32, 1);
    let rows = strings.len();
    let mut buf = vec![0u8; rows * width];
    for (i, s) in strings.iter().enumerate() {
        for (j, &b) in s.as_bytes().iter().enumerate() {
            buf[rows * j + i] = b;
        }
    }
    out.extend_from_slice(&buf);
}

pub fn filterSimulationResults(mut inFile: ArcStr, mut outFile: ArcStr, mut vars: Arc<metamodelica::List<ArcStr>>, mut numberOfIntervals: i32, mut removeDescription: bool, mut hintReadAllVars: bool) -> Result<bool> {
    // C: SimulationResults_filterSimulationResults — copy a result file keeping
    // only the requested variables (optionally resampled to `numberOfIntervals`
    // intervals). Only MATLAB v4 input is supported, matching the C switch.
    //
    // `hintReadAllVars` is a performance hint in the C reader (pre-read every
    // column); the Rust reader always loads data_2 in one pass, so it is a no-op.
    let mut reader = match ResultReader::open_reporting(&inFile)? {
        Some(ResultReader::Mat(r)) => r,
        Some(ResultReader::Csv(_)) => {
            err(&ERROR_FILTER_FORMAT, [ArcStr::from("CSV")])?;
            return Ok(false);
        }
        Some(ResultReader::Plt(_)) => {
            err(&ERROR_FILTER_FORMAT, [ArcStr::from("PLT")])?;
            return Ok(false);
        }
        None => return Ok(false),
    };

    // The C code prepends "time" to the requested variables.
    let mut var_names: Vec<ArcStr> = Vec::with_capacity(1 + vars.as_ref().into_iter().count());
    var_names.push(ArcStr::from("time"));
    var_names.extend(vars.as_ref().into_iter().cloned());
    let num_to_filter = var_names.len();

    // Look up every requested variable up front (so the trajectory reads below
    // can borrow the reader mutably).
    let mut fvars: Vec<FilterVar> = Vec::with_capacity(num_to_filter);
    for name in &var_names {
        let Some(idx) = reader.find_var(name.as_str()) else {
            err(&ERROR_COULD_NOT_READ_VAR, [name.clone(), openmodelica_util::System::basename(inFile.clone())])?;
            return Ok(false);
        };
        let info = &reader.allInfo[idx];
        fvars.push(FilterVar {
            name: info.name.clone(),
            descr: info.descr.clone(),
            isParam: info.isParam,
            index: info.index,
        });
    }

    let start = reader.start_time();
    let stop = reader.stop_time();

    // CSV output: a plain text table; parameters are rejected.
    if outFile.ends_with(".csv") {
        let mut cols: Vec<Vec<f64>> = Vec::with_capacity(num_to_filter);
        for fv in &fvars {
            if fv.isParam {
                err(&ERROR_FILTER_PARAM_CSV, [ArcStr::from(fv.name.as_str())])?;
                return Ok(false);
            }
            let Some(vals) = reader.read_vals(fv.index) else {
                err(&ERROR_COULD_NOT_READ_VAR, [ArcStr::from(fv.name.as_str()), openmodelica_util::System::basename(inFile.clone())])?;
                return Ok(false);
            };
            cols.push(vals);
        }
        let mut text = String::from("time");
        for fv in &fvars[1..] {
            text.push_str(",\"");
            text.push_str(&fv.name);
            text.push('"');
        }
        text.push('\n');
        for row in 0..reader.nrows {
            text.push_str(&format_g_prec15(cols[0][row]));
            for col in &cols[1..] {
                text.push(',');
                text.push_str(&format_g_prec15(col[row]));
            }
            text.push('\n');
        }
        if write_output_file(outFile.as_str(), text.as_bytes()).is_err() {
            err(&ERROR_FILTER_WRITE_FAILED, [outFile.clone()])?;
            return Ok(false);
        }
        return Ok(true);
    }

    // MATLAB v4 output. Tally which input data_1/data_2 columns are referenced
    // and build the old-index -> new-index remap, reserving data_1 column 1 for
    // the synthetic time start/stop pair.
    let nvar = reader.nvar;
    let nparam = reader.nparam;
    let mut indexes = vec![0i32; nvar];
    let mut parameter_indexes = vec![0i32; nparam];
    if nparam > 0 {
        parameter_indexes[0] = 1; // data_1 column 1 = time interval (always present)
    }
    let mut num_unique = 0usize;
    let mut num_unique_param = 1usize; // counts the reserved time column
    let mut longest_name = 0usize;
    let mut longest_desc = 0usize;
    for fv in &fvars {
        let slot = (fv.index.unsigned_abs() as usize) - 1;
        if fv.isParam {
            if parameter_indexes[slot] == 0 {
                num_unique_param += 1;
            }
            parameter_indexes[slot] += 1;
        } else {
            if indexes[slot] == 0 {
                num_unique += 1;
            }
            indexes[slot] += 1;
        }
        longest_name = longest_name.max(fv.name.len());
        longest_desc = longest_desc.max(fv.descr.len());
    }

    // indexesToOutput[k] = old (1-based) column of the k-th distinct variable;
    // `indexes` is then overwritten with the old->new lookup table.
    let mut indexes_to_output: Vec<i32> = Vec::with_capacity(num_unique);
    let mut j = 0i32;
    for i in 0..nvar {
        if indexes[i] != 0 {
            indexes_to_output.push((i + 1) as i32);
            j += 1;
        }
        indexes[i] = j;
    }
    let mut parameter_indexes_to_output: Vec<i32> = Vec::with_capacity(num_unique_param);
    let mut j = 0i32;
    for i in 0..nparam {
        if parameter_indexes[i] != 0 {
            parameter_indexes_to_output.push((i + 1) as i32);
            j += 1;
        }
        parameter_indexes[i] = j;
    }

    let mut out: Vec<u8> = Vec::new();
    // Aclass (binNormal): 4x11 char matrix, column 3 spelling "binNormal".
    const ACLASS_NORMAL: &[u8] = b"A1 bt. ir1 na  Nj  oe  rc  mt  ao  lr   y   ";
    debug_assert_eq!(ACLASS_NORMAL.len(), 4 * 11);
    push_mat_header(&mut out, "Aclass", 4, 11, 1);
    out.extend_from_slice(ACLASS_NORMAL);

    // name matrix.
    let names: Vec<&str> = fvars.iter().map(|f| f.name.as_str()).collect();
    push_char_matrix(&mut out, "name", &names, longest_name);
    // description matrix: removeDescription emits the same numToFilter rows but
    // with zero-width (empty) entries, matching the C `width=0` header.
    if removeDescription {
        push_char_matrix(&mut out, "description", &vec![""; num_to_filter], 0);
    } else {
        let descrs: Vec<&str> = fvars.iter().map(|f| f.descr.as_str()).collect();
        push_char_matrix(&mut out, "description", &descrs, longest_desc);
    }

    // dataInfo: numToFilter rows x 4 cols (isParam/index/interpolation/defined),
    // written column-major (all of column k contiguously).
    push_mat_header(&mut out, "dataInfo", num_to_filter as u32, 4, 4);
    for fv in &fvars {
        let x: i32 = if fv.isParam { 1 } else { 2 }; // data_1 vs data_2
        out.extend_from_slice(&x.to_le_bytes());
    }
    for fv in &fvars {
        let slot = (fv.index.unsigned_abs() as usize) - 1;
        let new_index = if fv.isParam { parameter_indexes[slot] } else { indexes[slot] };
        let x = if fv.index < 0 { -new_index } else { new_index };
        out.extend_from_slice(&x.to_le_bytes());
    }
    for _ in &fvars {
        out.extend_from_slice(&0i32.to_le_bytes()); // linear interpolation
    }
    for _ in &fvars {
        out.extend_from_slice(&(-1i32).to_le_bytes()); // not defined outside interval
    }

    // data_1: 2 rows x numUniqueParam cols. Column 0 = {start, stop}; the rest
    // are the constant parameter values (stored twice).
    push_mat_header(&mut out, "data_1", 2, num_unique_param as u32, 8);
    out.extend_from_slice(&start.to_le_bytes());
    out.extend_from_slice(&stop.to_le_bytes());
    for i in 1..num_unique_param {
        let param_index = parameter_indexes_to_output[i];
        let p = reader.params[(param_index.unsigned_abs() as usize) - 1];
        out.extend_from_slice(&p.to_le_bytes());
        out.extend_from_slice(&p.to_le_bytes());
    }

    // Optional resampling notification: count the events that fall away when
    // re-gridding to numberOfIntervals equidistant points.
    if numberOfIntervals != 0 {
        let timevals = reader.read_vals(1).unwrap_or_default();
        let mut nevents = 0i32;
        let mut neventpoints = 0i32;
        let mut k = 0usize;
        for i in 1..numberOfIntervals {
            let t = start + (stop - start) * (i as f64) / (numberOfIntervals as f64);
            while k < timevals.len() && timevals[k] <= t {
                if k + 1 < timevals.len() && timevals[k] == timevals[k + 1] {
                    while k + 1 < timevals.len() && timevals[k] == timevals[k + 1] {
                        k += 1;
                        neventpoints += 1;
                    }
                    nevents += 1;
                }
                k += 1;
            }
        }
        err(&NOTIFY_RESAMPLING, [
            inFile.clone(),
            ArcStr::from(reader.nrows.to_string()),
            ArcStr::from(numberOfIntervals.to_string()),
            ArcStr::from(nevents.to_string()),
            ArcStr::from(neventpoints.to_string()),
        ])?;
    }

    // data_2: (numberOfIntervals+1 | nrows) rows x numUnique cols, each column a
    // variable trajectory written contiguously (column-major).
    let out_rows = if numberOfIntervals != 0 { (numberOfIntervals + 1) as usize } else { reader.nrows };
    push_mat_header(&mut out, "data_2", out_rows as u32, num_unique as u32, 8);
    for &col in &indexes_to_output {
        if numberOfIntervals != 0 {
            for jj in 0..=numberOfIntervals {
                let t = if jj == numberOfIntervals {
                    stop
                } else {
                    start + (stop - start) * (jj as f64) / (numberOfIntervals as f64)
                };
                let Some(v) = reader.interp_val(col, t) else {
                    err(&ERROR_RESAMPLE_FAILED, [
                        inFile.clone(),
                        ArcStr::from(col.to_string()),
                        ArcStr::from(format_g_prec15(t)),
                    ])?;
                    return Ok(false);
                };
                out.extend_from_slice(&v.to_le_bytes());
            }
        } else {
            let Some(vals) = reader.read_vals(col) else {
                err(&ERROR_COULD_NOT_READ_VAR, [ArcStr::from("data_2"), openmodelica_util::System::basename(inFile.clone())])?;
                return Ok(false);
            };
            for v in vals {
                out.extend_from_slice(&v.to_le_bytes());
            }
        }
    }

    if write_output_file(outFile.as_str(), &out).is_err() {
        err(&ERROR_FILTER_WRITE_FAILED, [outFile.clone()])?;
        return Ok(false);
    }
    Ok(true)
}
